        Path pluginJar = Path.of(args[0]);
        int cycles = args.length > 1 ? Integer.parseInt(args[1]) : 500;

        try (TextDaemon daemon = new TextDaemon(pluginJar, 2)) {
            for (int generation = 1; generation <= cycles; generation++) {
